    //MARK: WHERE RULE VALIDATION (SELECT TYPE)
    public static func validateWhereRules(instance:Self?, prefix:SDAI.WhereLabel) -> SDAI.WhereRuleValidationRecords {
      var result: SDAI.WhereRuleValidationRecords = [:]
      switch instance {
      case ._ACTION_REQUEST_SOLUTION(let entity): 
        if !entity.shouldPropagateValidation { break }
        result = eACTION_REQUEST_SOLUTION.validateWhereRules(instance: entity.eval, 
        prefix:prefix + "\\\(entity)")
      case ._APPLICATION_CONTEXT(let entity): 
        if !entity.shouldPropagateValidation { break }
        result = eAPPLICATION_CONTEXT.validateWhereRules(instance: entity.eval, 
        prefix:prefix + "\\\(entity)")
      case ._APPROVAL_ROLE(let entity): 
        if !entity.shouldPropagateValidation { break }
        result = eAPPROVAL_ROLE.validateWhereRules(instance: entity.eval, prefix:prefix + "\\\(entity)")
      case ._CONFIGURATION_DESIGN(let entity): 
        if !entity.shouldPropagateValidation { break }
        result = eCONFIGURATION_DESIGN.validateWhereRules(instance: entity.eval, 
        prefix:prefix + "\\\(entity)")
